using namespace std;using ll = long long;int main() {if(1){freopen("angry.in", "r", stdin);freopen("angry.out", "w", stdout);}int N;cin >> N;vector<int> pos(N);for (int i = 0; i < N; i++) cin >> pos[i];sort(pos.begin(), pos.end());int l = 0, r = 2e9, ans = 2e9;while (l <= r) {int mid = (l + r) / 2;double R = mid / 10.0;bool possible = false;  for (int i = 0; i < N-1; i++) {    double startPos = pos[i];    int left = i, right = i;    double radius = R;    while (radius > 0) {        int newLeft = left;        while (newLeft > 0 && startPos - pos[newLeft - 1] <= radius) {            newLeft--;        }        int newRight = right;        while (newRight < N - 1 && pos[newRight + 1] - startPos <= radius) {            newRight++;        }        if (newLeft == left && newRight == right) break;        left = newLeft;        right = newRight;        radius -= 1.0;    }    if (left == 0 && right == N - 1) {        possible = true;        break;    }      for (int offset = 1; offset <= 9; offset++) {        startPos = pos[i] + offset * 0.1;        if (startPos >= pos[i+1]) break; left = i;        while (left > 0 && startPos - pos[left-1] <= R) left--;        right = i;        while (right < N-1 && pos[right+1] - startPos <= R) right++;                double rad = R - 1.0;        while (rad > 0 && (left > 0 || right < N-1)) {            int newLeft = left;            while (newLeft > 0 && pos[left] - pos[newLeft-1] <= rad) newLeft--;            int newRight = right;            while (newRight < N-1 && pos[newRight+1] - pos[right] <= rad) newRight++;            if (newLeft == left && newRight == right) break;            left = newLeft;            right = newRight;            rad -= 1.0;        }        if (left == 0 && right == N - 1) {            possible = true;            break;        }    }    if (possible) break;}if (possible) {ans = mid;r = mid - 1;} else {l = mid + 1;}}cout << fixed << setprecision(1) << ans / 10.0 << '\n';return 0;}
